// prefill_attn.cu — scale-free causal-mask + softmax over the prefill attention
// scores, the middle (Step 2) of the GPU batched-attention path. The two GEMMs
// around it (QKᵀ and AV) run through cuBLAS `sgemmStridedBatched` in
// cuda_matmul.rs; this kernel only turns raw scores into a causal softmax,
// in place, so the AV GEMM that follows consumes a valid probability row.
//
// WHY a custom kernel (cuBLAS cannot do this): the softmax is row-local with a
// per-row causal cutoff (query t attends only keys j ≤ start_pos+q_off+t), and
// the masked tail must become exactly 0 so the subsequent full-width AV GEMM
// over all L keys reproduces the CPU path that sums only j∈[0,pos]. That is a
// reduction + elementwise transform, not a matmul.
//
// SCALE: the 1/sqrt(head_dim) factor is folded into the QKᵀ GEMM's `alpha` in
// cuda_matmul.rs, so the scores reaching this kernel are ALREADY scaled. This
// kernel does NOT scale — it only masks + softmaxes, matching the CPU order
// (scores → divide by sqrt(d) → softmax) bit-for-bit to f32 tolerance.
//
// ─────────────────────────────────────────────────────────────────────────
// LAYOUT / WORK MAPPING:
//   scores is row-major [num_heads × Tq × L]: row r = h*Tq + t starts at r*L,
//   contiguous over the L key columns. ONE CUDA BLOCK softmaxes ONE row r
//   (blockIdx.x = r), with blockDim.x = a power of two (256). Threads stride
//   over the L columns; two shared-memory tree reductions (max, then sum) give
//   the row max and the normalizer. The causal-valid prefix length for row r is
//   `valid = start_pos + q_off + (r % Tq) + 1` (clamped to L); columns ≥ valid
//   are written 0.
//
// This mirrors the CPU Phase-B `softmax(att_slice)` where `att_slice` has length
// `pos+1` (the causal prefix), so the math is identical for the valid columns
// and the masked tail contributes 0 through AV — exactly as the CPU loop that
// only accumulates t∈[0,pos].

extern "C" __global__ void prefill_attn_softmax(
    float* scores,   // [num_heads * Tq * L] row-major, modified in place
    int Tq,          // query rows per head in this tile
    int L,           // allocated key-column width (>= max valid prefix)
    int start_pos,   // absolute position of the FIRST query in the chunk
    int q_off)       // this tile's query offset within the chunk
{
    const int r = blockIdx.x;          // global row over [num_heads * Tq]
    const int t = r % Tq;              // query index within its head
    float* row = scores + (size_t)r * (size_t)L;

    // Causal cutoff: query absolute position attends keys [0, qpos]; valid count
    // = qpos + 1. Clamp to L (by construction qpos+1 <= L for the benchmarked
    // single-chunk path, but clamp defensively so a ragged tile can't overrun).
    int valid = start_pos + q_off + t + 1;
    if (valid > L) valid = L;
    if (valid < 0) valid = 0;

    extern __shared__ float sh[];      // blockDim.x floats
    const int tid = threadIdx.x;
    const int nthreads = blockDim.x;

    // ── Pass 1: row max over [0, valid) ────────────────────────────────────
    float local_max = -INFINITY;
    for (int j = tid; j < valid; j += nthreads) {
        float v = row[j];
        if (v > local_max) local_max = v;
    }
    sh[tid] = local_max;
    __syncthreads();
    for (int s = nthreads >> 1; s > 0; s >>= 1) {
        if (tid < s) {
            float o = sh[tid + s];
            if (o > sh[tid]) sh[tid] = o;
        }
        __syncthreads();
    }
    const float row_max = sh[0];
    __syncthreads();

    // ── Pass 2: exp(x - max) in place + sum ────────────────────────────────
    float local_sum = 0.0f;
    for (int j = tid; j < valid; j += nthreads) {
        float e = expf(row[j] - row_max);
        row[j] = e;
        local_sum += e;
    }
    sh[tid] = local_sum;
    __syncthreads();
    for (int s = nthreads >> 1; s > 0; s >>= 1) {
        if (tid < s) sh[tid] += sh[tid + s];
        __syncthreads();
    }
    const float row_sum = sh[0];
    __syncthreads();

    // ── Pass 3: normalize valid columns, zero the masked tail ──────────────
    // row_sum > 0 always (valid >= 1 → at least exp(0)=1 contributes), but guard
    // against a degenerate valid==0 tile so we never divide by zero.
    const float inv = (row_sum > 0.0f) ? (1.0f / row_sum) : 0.0f;
    for (int j = tid; j < L; j += nthreads) {
        row[j] = (j < valid) ? row[j] * inv : 0.0f;
    }
}
